import{_ as l,o as e,c as i,a2 as r}from"./chunks/framework.BEgbRHOA.js";const p=JSON.parse('{"title":"Управление товарами","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier-manager/products.md","filePath":"guide/xcourier-manager/products.md","lastUpdated":1775746985000}'),t={name:"guide/xcourier-manager/products.md"};function o(n,a,d,u,c,s){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="управление-товарами" tabindex="-1">Управление товарами <a class="header-anchor" href="#управление-товарами" aria-label="Permalink to &quot;Управление товарами&quot;">​</a></h1><h2 id="каталог-товаров" tabindex="-1">Каталог товаров <a class="header-anchor" href="#каталог-товаров" aria-label="Permalink to &quot;Каталог товаров&quot;">​</a></h2><p>Страница товаров показывает весь ассортимент магазина менеджера. Доступны режимы отображения:</p><ul><li><strong>Сетка</strong> — карточки с изображениями</li><li><strong>Список</strong> — компактный вид с основной информацией</li></ul><h2 id="фильтрация" tabindex="-1">Фильтрация <a class="header-anchor" href="#фильтрация" aria-label="Permalink to &quot;Фильтрация&quot;">​</a></h2><p>Товары можно фильтровать:</p><ul><li>По категориям (отдельная страница выбора категорий)</li><li>По наличию (страница «Нет в наличии» для быстрого управления стоком)</li><li>Поиск по названию</li></ul><h2 id="добавление-товара" tabindex="-1">Добавление товара <a class="header-anchor" href="#добавление-товара" aria-label="Permalink to &quot;Добавление товара&quot;">​</a></h2><p>Для создания нового товара менеджер заполняет:</p><ul><li>Название товара</li><li>Цена (в тенге)</li><li>Вес/объём</li><li>Описание (опционально)</li><li>Категории (мультивыбор)</li><li>Фотография товара (загружается через Cloud Function <code>uploadImage</code>, конвертируется в WebP)</li><li>Флаг наличия (inStock)</li></ul><h2 id="редактирование-товара" tabindex="-1">Редактирование товара <a class="header-anchor" href="#редактирование-товара" aria-label="Permalink to &quot;Редактирование товара&quot;">​</a></h2><p>Менеджер может изменить любое поле существующего товара:</p><ul><li>Обновить цену</li><li>Сменить изображение (старое автоматически удаляется из хранилища)</li><li>Изменить категории</li><li>Переключить наличие</li></ul><h2 id="управление-наличием" tabindex="-1">Управление наличием <a class="header-anchor" href="#управление-наличием" aria-label="Permalink to &quot;Управление наличием&quot;">​</a></h2><p>Отдельная страница «Нет в наличии» показывает только товары с <code>inStock: false</code>. Менеджер может быстро вернуть товар в наличие переключателем.</p><h2 id="категории" tabindex="-1">Категории <a class="header-anchor" href="#категории" aria-label="Permalink to &quot;Категории&quot;">​</a></h2><p>Доступна отдельная страница управления категориями магазина:</p><ul><li>Создание новой категории</li><li>Изменение порядка сортировки</li><li>Активация/деактивация категории</li></ul>',18)])])}const _=l(t,[["render",o]]);export{p as __pageData,_ as default};
